import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { ArrowLeft, Calendar, Award } from 'lucide-react';

const ExperienceDetail = () => {
  const { experienceId } = useParams();
  const navigate = useNavigate();

  const experiences = [
    {
      id: 0,
      company: "DigitalBee Labs",
      role: "Intern Software Engineer",
      period: "April 2025 – February 2026",
      description: "Full-Stack Developer on a Multi-Tenant SaaS Healthcare Platform, contributing to administrative dashboards, partner management systems, and AI-powered support projects.",
      longDescription: `As an Intern Software Engineer at DigitalBee Labs, I worked on multiple projects including:

- **Multi-Tenant SaaS Healthcare Platform:** Architected and developed a centralized backend using ASP.NET Core for 7 integrated applications with tenant isolation and secure data access. Engineered 200+ REST APIs with JWT authentication, refresh token rotation, and RBAC. Designed a PostgreSQL database (50+ tables) with strategic indexing. Integrated Lemon Squeezy for subscription management and global billing. Developed background services and webhook automation, reducing manual admin work by 40%. Applied OWASP and HIPAA security best practices.

- **Administrative Dashboard (Next.js):** Developed end-to-end dashboards for managing medical users, appointments, and platform configurations. Implemented server-side security middleware, global state management with React Context API, and responsive, accessible UI components.

- **Affiliate & Partner Management System:** Built using Vue.js and ASP.NET Core for onboarding and real-time revenue tracking. Implemented Webhooks and SignalR for zero-latency updates. Used Pinia for high-performance state management.

- **AI-Powered Smart Content Platform:** Developed FastAPI REST APIs connecting LLM-based AI models with frontend. Implemented Celery + Redis for async task processing. Built secure admin dashboards with Next.js.

- **Laravel + React CMS:** Restructured backend for modern React CMS, implemented OAuth authentication, optimized workflows, and email notifications.

- **Web Optimization & Core Web Vitals:** Enhanced high-traffic site performance with image optimization, asset minification, and SEO improvements.`,
      skills: ["ASP.NET Core", "Next.js", "React", "Vue.js", "FastAPI", "Laravel", "Celery", "Redis", "PostgreSQL", "JWT", "SignalR", "Pinia", "OAuth", "Web Optimization", "UI/UX Design"],
      achievements: [
        "Architected a centralized multi-tenant SaaS backend serving 7 integrated apps",
        "Engineered 200+ secure RESTful API endpoints with JWT and RBAC",
        "Developed end-to-end administrative dashboards in Next.js",
        "Automated clinical workflows with background services and webhooks, reducing manual work by 40%",
        "Built a real-time affiliate & partner revenue tracking system using SignalR",
        "Implemented AI-powered content platform with FastAPI and Celery for async processing",
        "Optimized Laravel + React CMS workflows and improved web performance and Core Web Vitals"
      ]
    }
  ];

  const experience = experiences.find(exp => exp.id === parseInt(experienceId));

  if (!experience) {
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-darkBg flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-3xl font-bold mb-4">Experience not found</h1>
          <button
            onClick={() => navigate('/')}
            className="px-6 py-2 bg-primary text-white rounded-lg hover:bg-primary/90"
          >
            Back to Home
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-darkBg">
      {/* Navigation Bar */}
      <nav className="sticky top-0 z-50 bg-white/95 dark:bg-darkBg/95 backdrop-blur-md border-b border-slate-200 dark:border-slate-800">
        <div className="container mx-auto px-6 py-4">
          <button
            onClick={() => navigate('/')}
            className="flex items-center gap-2 text-primary hover:gap-3 transition-all"
          >
            <ArrowLeft size={20} />
            <span className="font-semibold">Back to Home</span>
          </button>
        </div>
      </nav>

      {/* Main Content */}
      <div className="container mx-auto px-6 py-20">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
        >
          {/* Header Section */}
          <div className="mb-12">
            <div className="flex items-start justify-between mb-6">
              <div>
                <h1 className="text-5xl font-bold mb-2">{experience.role}</h1>
                <p className="text-2xl text-primary font-semibold">{experience.company}</p>
              </div>
              <div className="glass p-6 rounded-2xl text-right">
                <div className="flex items-center justify-end gap-2 mb-2">
                  <Calendar size={20} className="text-primary" />
                  <span className="text-lg font-semibold">{experience.period}</span>
                </div>
              </div>
            </div>

            <div className="prose dark:prose-invert max-w-none">
              <p className="text-xl text-slate-700 dark:text-slate-300 leading-relaxed">
                {experience.longDescription}
              </p>
            </div>
          </div>

          {/* Skills Section */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.2 }}
            className="mb-12"
          >
            <h2 className="text-2xl font-bold mb-6">Technologies & Skills</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {experience.skills.map((skill, index) => (
                <motion.div
                  key={skill}
                  initial={{ opacity: 0, scale: 0.8 }}
                  animate={{ opacity: 1, scale: 1 }}
                  transition={{ delay: 0.2 + index * 0.05 }}
                  className="glass p-4 rounded-xl border border-primary/10 hover:border-primary/30 transition-all"
                >
                  <p className="text-center font-semibold text-primary">{skill}</p>
                </motion.div>
              ))}
            </div>
          </motion.div>

          {/* Achievements Section */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.3 }}
          >
            <h2 className="text-2xl font-bold mb-6 flex items-center gap-2">
              <Award size={24} className="text-primary" />
              Key Achievements
            </h2>
            <div className="space-y-4">
              {experience.achievements.map((achievement, index) => (
                <motion.div
                  key={index}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.3 + index * 0.1 }}
                  className="glass p-6 rounded-2xl border-l-4 border-primary"
                >
                  <p className="text-slate-700 dark:text-slate-300 text-lg">
                    {achievement}
                  </p>
                </motion.div>
              ))}
            </div>
          </motion.div>
        </motion.div>
      </div>
    </div>
  );
};

export default ExperienceDetail;
